// Fusion Ai 品牌资产（P2-1 品牌化导出）。源自用户提供的范本 Word（智能导诊方案）的页眉横幅与
// 封面 logo，提取并内嵌为 base64——不落磁盘、不依赖打包资源路径（asar 路径在 dev/prod 不一致，
// base64 内联最稳）。main（proposalDocx 嵌入 ImageRun）与 renderer（预览/PDF 同源渲染）共享。
//
// 三张图均为透明底 PNG：
//  - HEADER_BANNER：右对齐 Fusion Ai logo + 橙色分隔线，铺每页页眉（宽幅，约 8.7:1）。
//  - COVER_LOGO：完整 Fusion Ai 标志（火焰 + 文字），封面顶部右对齐。
//  - COVER_FLAME：仅火焰图标，封面左侧浮动装饰（源文档 anchor 在文字后方）。
// 像素尺寸随附（ImageRun 的 transformation 用 px；docx 库内部转 EMU）。

export interface BrandAsset {
  /** 纯 base64（不含 data: 前缀）。main 用 Buffer.from(.., 'base64')，renderer 拼 data URL。 */
  base64: string
  /** 原始像素宽。 */
  width: number
  /** 原始像素高。 */
  height: number
}

export const FUSION_HEADER_BANNER: BrandAsset = {
  width: 1247,
  height: 144,
  base64:
    ''
}

export const FUSION_COVER_LOGO: BrandAsset = {
  width: 367,
  height: 83,
  base64:
    ''
}

export const FUSION_COVER_FLAME: BrandAsset = {
  width: 171,
  height: 342,
  base64:
    ''
}
